// 1. OBTENEMOS LA CAPACIDAD DINÁMICA
// Extraemos el valor del nodo "Obtiene Capacidad Reservas" según se ve en tu captura
let CAPACIDAD_TOTAL = 0;
try {
  CAPACIDAD_TOTAL = Number($('Obtiene Capacidad Reservas').first().json.capacidadreservas) || 0;
} catch (error) {
  // Valor de respaldo en caso de que el nodo no esté disponible
  CAPACIDAD_TOTAL = 45; 
}

// 2. OBTENER LA PETICIÓN DEL CLIENTE (Agente Principal)
let solicitud;
try {
  solicitud = $('Agente Principal').first().json;
} catch (error) {
  solicitud = { num_personas: 0 };
}

const personasRequeridas = Number(solicitud.num_personas) || 0;

// 3. CALCULAR LA OCUPACIÓN ACTUAL (Viene de la base de datos)
const items = $input.all();
let ocupadasActualmente = 0;

for (const item of items) {
  ocupadasActualmente += Number(item.json.num_personas) || 0;
}

// 4. CÁLCULOS
const libres = Math.max(0, CAPACIDAD_TOTAL - ocupadasActualmente);
const hayLugar = (personasRequeridas > 0) && (personasRequeridas <= libres);

// 5. GENERAR RESPUESTA
let mensaje = "";
let estado = "";

if (hayLugar) {
  mensaje = `Disponible: Quedan ${libres} lugares y solicitaste ${personasRequeridas}.`;
  estado = "disponible";
} else {
  if (libres === 0) {
    mensaje = "Agotado: No quedan lugares disponibles.";
    estado = "agotado";
  } else if (personasRequeridas > libres) {
    mensaje = `Capacidad insuficiente: Solo quedan ${libres} lugares (solicitaste ${personasRequeridas}).`;
    estado = "insuficiente";
  } else {
    mensaje = "No se especificó un número válido de personas.";
    estado = "error_solicitud";
  }
}

return [
  {
    json: {
      req_personas: personasRequeridas,
      total_ocupadas: ocupadasActualmente,
      capacidad_maxima: CAPACIDAD_TOTAL,
      lugares_restantes: libres,
      hay_disponibilidad: hayLugar,
      disponibilidad_texto: mensaje,
      estado_disponibilidad: estado
    }
  }
];

