// Nodo Code (JavaScript) en n8n
const items = $input.all();
const TIMEZONE = 'America/Buenos_Aires'; // <--- AJUSTA ESTO SI ES NECESARIO

// Helper para obtener la fecha/hora actual en la zona horaria específica
// Retorna un objeto Date que representa la "hora reloj" en México
function getNowInTimezone() {
  const d = new Date();
  // Convertimos la hora UTC del servidor a string en hora local México
  const localStr = d.toLocaleString('en-US', { timeZone: TIMEZONE });
  return new Date(localStr);
}

function getTodayAtMidnight(nowReference) {
  const d = new Date(nowReference.getTime());
  d.setHours(0, 0, 0, 0);
  return d;
}

function addMonths(date, months) {
  const d = new Date(date.getTime());
  const day = d.getDate();
  d.setMonth(d.getMonth() + months);
  if (d.getDate() < day) {
    d.setDate(0);
  }
  d.setHours(23, 59, 59, 999);
  return d;
}

function getWeekdayNameES(date) {
  // Nota: Al crear el formateador, forzamos la zona horaria para asegurar el día correcto
  const weekday = new Intl.DateTimeFormat('es-AR', {
    weekday: 'long',
    timeZone: TIMEZONE 
  }).format(date);
  return weekday.charAt(0).toUpperCase() + weekday.slice(1);
}

function pad2(n) {
  return n.toString().padStart(2, '0');
}

function calcularMesasSugeridas(numPersonas) {
  if (numPersonas == null || isNaN(numPersonas) || numPersonas <= 0) {
    return null; 
  }
  if (numPersonas <= 2) return 1;
  if (numPersonas <= 4) return 2;
  if (numPersonas <= 6) return 3;
  return 'VIP';
}

// 1. Definimos el "Ahora" y el "Hoy" basados en México, no en el servidor UTC
const now = getNowInTimezone();
const today = getTodayAtMidnight(now);
const maxDate = addMonths(today, 3);

const out = items.map(item => {
  const data = item.json;

  const fechaStr    = data['fecha (YYYY-MM-DD)'];
  const horaStr     = data.hora;
  const numPersonas = data.num_personas != null ? Number(data.num_personas) : null;

  let escenarioRestrictivo = null;
  let leyenda = '';
  let esValida = true;

  const [y, m, d] = (fechaStr || '').split('-').map(Number);
  const [hh, mm]  = (horaStr || '').split(':').map(Number);

  // Fecha base (00:00) construida con los datos de entrada
  const fechaSolo = new Date(y, m - 1, d);
  fechaSolo.setHours(0, 0, 0, 0);

  // Validaciones de rango (comparando fechas "reloj" contra fechas "reloj")
  if (fechaSolo < today) {
    esValida = false;
    escenarioRestrictivo = 'fecha_pasada';
    leyenda = 'La fecha a reservar es anterior al día de hoy.';
  } else if (fechaSolo > maxDate) {
    esValida = false;
    escenarioRestrictivo = 'fecha_fuera_rango_3_meses';
    leyenda = 'La fecha excede el límite de 3 meses para crear reservaciones.';
  }

  // Objeto Fecha+Hora entrada
  let fechaHora = new Date(y, m - 1, d, hh, mm || 0, 0, 0);

  // Lógica de "Menos de 1 hora"
  if (esValida && fechaSolo.getTime() === today.getTime()) {
    // Calculamos diferencia en ms entre la entrada y el "ahora" de México
    const diffMs = fechaHora.getTime() - now.getTime();
    const diffMin = diffMs / 60000;

    // IMPORTANTE: Verificamos que diffMin sea positivo (futuro) y menor a 60
    // Si diffMin es negativo, significa que la hora ya pasó hoy.

    if (diffMin < 0) {
       // Opcional: Si la hora ya pasó hoy, ¿es inválida?
       // Por ahora asumiremos que se ajusta igual que si faltara poco
       // O podrías marcarla como inválida. Aquí mantengo la lógica de ajuste.
    }

    // La regla: Si estamos a menos de 60 minutos (incluyendo si ya pasó hace poco)
    // Nota: Si quieres que solo aplique a futuro cercano usa: (diffMin > 0 && diffMin < 60)
    // Si dejas solo (diffMin < 60) ajustará también horas pasadas del día de hoy.
    if (diffMin < 60) {

      // Tomamos la hora actual de México ('now') y sumamos 1 hora
      const nextHour = new Date(now.getTime());
      nextHour.setMinutes(0, 0, 0);
      nextHour.setHours(nextHour.getHours() + 1);

      fechaHora = nextHour;

      escenarioRestrictivo = 'menos_de_una_hora';
      leyenda = 'No se pudo validar disponibilidad. Reservas con por lo menos 1 hora de anticipación, ofrece un poco más tarde o escala con humano (integrante del equipo) para una gestión manual.';
    }
  }

  // Generar salida final basada en fechaHora (que pudo haber cambiado de día)
  const finalYear = fechaHora.getFullYear();
  const finalMonth = fechaHora.getMonth() + 1;
  const finalDay = fechaHora.getDate();
  const finalHour = fechaHora.getHours();
  const finalMinute = fechaHora.getMinutes();

  const fechaNormalizada = `${finalYear}-${pad2(finalMonth)}-${pad2(finalDay)}`;
  const horaNormalizada  = `${pad2(finalHour)}:${pad2(finalMinute)}`;
  const diaSemana = getWeekdayNameES(fechaHora);

  const mesasSugeridas = calcularMesasSugeridas(numPersonas);

  const resultado = {
    fecha_original: fechaStr,
    hora_original: horaStr,
    num_personas_original: numPersonas,

    fecha_normalizada: fechaNormalizada,
    hora_normalizada: horaNormalizada,
    dia_semana: diaSemana,

    // Aquí están los campos separados que pediste
    hora: finalHour,
    minutos: finalMinute,

    fecha_hora_iso: fechaHora.toISOString(), // Nota: esto saldrá en la ISO del 'falso local', útil para logs
    num_personas: numPersonas,
    mesas_sugeridas: mesasSugeridas,

    es_valida: esValida,
    escenario_restrictivo: escenarioRestrictivo,
    leyenda: escenarioRestrictivo ? leyenda : 'Selección válida.'
  };

  return { json: resultado };
});

return out;

